import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, throwError } from 'rxjs';
import { catchError } from 'rxjs/operators';

@Injectable({
  providedIn: 'root'
})
export class LoggingService {
  private apiUrl = 'https://m1jp17h33i.execute-api.eu-west-2.amazonaws.com/default/LinkSelection';

  constructor(private http: HttpClient) {}

  // When button is clicked
  logButtonClick(buttonClicked: string): Observable<any> {
    const data = { buttonClicked };

    try {
      // Convert to JSON format
      const lambdaPayload = {
        body: JSON.stringify(data),
      };

      console.log('Payload:', data);

      return this.http.post(this.apiUrl, lambdaPayload).pipe(
        catchError((error) => {
          console.error('HTTP Request Error:', error);
          return throwError(error);
        })
      );
    } catch (error) {
      console.error('Error converting to JSON:', error);
      return throwError('Error converting to JSON');
    }
  }
}
